from dataclasses import dataclass
from typing import List

@dataclass
class Account:
    account_number: int
    balance: float

def initialize_accounts() -> List[Account]:
    accounts = [
        Account(account_number=1001, balance=1500.0),
        Account(account_number=1002, balance=2500.0),
        Account(account_number=1003, balance=3500.0),
    ]
    return accounts

def find_account(accounts: List[Account], account_number: int) -> Account:
    for account in accounts:
        if account.account_number == account_number:
            return account
    raise ValueError("Account not found")

def deposit(account: Account, amount: float) -> None:
    account.balance += amount

def withdraw(account: Account, amount: float) -> None:
    if account.balance >= amount:
        account.balance -= amount
    else:
        raise ValueError("Insufficient funds")

def display_account(account: Account) -> None:
    print(f"Account Number: {account.account_number} Balance: {account.balance:.2f}")

def main() -> None:
    accounts = initialize_accounts()
    try:
        account = find_account(accounts, 1001)
        deposit(account, 500.0)
        withdraw(account, 200.0)
        display_account(account)
    except ValueError as e:
        print(e)

if __name__ == "__main__":
    main()
